import{_ as e,o as a,c as l,a2 as n}from"./chunks/framework.DnrXFDHb.js";const F=JSON.parse('{"title":"F02: 營業現金流與獲利品質 - finance-financial-analyst 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/3189_景碩/20260423/F02_營業現金流與獲利品質_財務分析專家_審計報告.md","filePath":"審計報告庫/財務審計/3189_景碩/20260423/F02_營業現金流與獲利品質_財務分析專家_審計報告.md"}'),i={name:"審計報告庫/財務審計/3189_景碩/20260423/F02_營業現金流與獲利品質_財務分析專家_審計報告.md"};function r(d,t,c,o,s,_){return a(),l("div",null,[...t[0]||(t[0]=[n('<h1 id="f02-營業現金流與獲利品質-finance-financial-analyst-審計報告" tabindex="-1">F02: 營業現金流與獲利品質 - finance-financial-analyst 審計報告 <a class="header-anchor" href="#f02-營業現金流與獲利品質-finance-financial-analyst-審計報告" aria-label="Permalink to &quot;F02: 營業現金流與獲利品質 - finance-financial-analyst 審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>營業活動現金流量 (CFO) 與稅後淨利之關係為何？獲利是否具備實質現金支撐？</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>截至2025年度最新公開數據，景碩合併CFO/合併淨利比值達298%，歸屬母公司CFO/母公司淨利比值達507%，顯示獲利具極高現金含金量。但CFO主力來源為折舊費用(佔CFO 88%)，扣除折舊後營運資金變動貢獻為負值，FCF在2025年才轉正至17.1億元。判定獲利品質A（良）但存在資本密集依賴之結構性隱憂。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p><strong>評級：A（良）</strong> — CFO與淨利長期同步增長，CFO/Net Income比值持續高於100%，顯示帳面獲利有充分現金支撐。但以下關鍵數據需穿透解讀：(1)合併淨利2025年27.17億元 vs CFO 80.93億元，比值298%，但折舊71.6億元佔CFO比例達88.5%，扣除折舊後CFO僅9.3億元。(2)營運資金變動在2025年為淨流出21.2億元(應收增15.1億+存貨增15.0億+應付增17.9億)。(3)自由現金流(FCF)2025年轉正至17.1億元(CFO 80.9億 - 資本支出63.8億)，但仍低於折舊規模，顯示尚無法自給自足覆蓋產能擴張需求，仍需仰賴借款支撐。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><p><strong>1. CFO/Net Income四年度對比（合併報表口徑）：</strong></p><table tabindex="0"><thead><tr><th style="text-align:center;">年度</th><th style="text-align:center;">CFO(百萬)</th><th style="text-align:center;">合併淨利(百萬)</th><th style="text-align:center;">CFO/淨利比</th><th style="text-align:center;">母公司淨利(百萬)</th><th style="text-align:center;">CFO/母公司淨利比</th></tr></thead><tbody><tr><td style="text-align:center;">2023</td><td style="text-align:center;">6,256</td><td style="text-align:center;">1,170</td><td style="text-align:center;">534%</td><td style="text-align:center;">47.5</td><td style="text-align:center;">13,170%</td></tr><tr><td style="text-align:center;">2024</td><td style="text-align:center;">7,705</td><td style="text-align:center;">1,331</td><td style="text-align:center;">579%</td><td style="text-align:center;">48.9</td><td style="text-align:center;">15,760%</td></tr><tr><td style="text-align:center;">2025</td><td style="text-align:center;">8,093</td><td style="text-align:center;">2,717</td><td style="text-align:center;">298%</td><td style="text-align:center;">1,596</td><td style="text-align:center;">507%</td></tr></tbody></table><p>CFO/合併淨利比在2023-2024年處於500%以上超高水位，主因淨利基數極低(因業主淨利僅4,700-4,900萬)，而CFO因高折舊而持續大額流入。2025年母公司淨利回升至15.96億元後，比值自然回落至507%，仍屬優異水準。</p><p><strong>2. 非現金項目核實：</strong></p><ul><li>折舊費用為CFO最核心支柱：2023年52.8億/2024年60.7億/2025年71.6億，分別佔CFO的84.4%/78.7%/88.5%。</li><li>收益費損項目合計：2023年52.8億/2024年59.0億/2025年72.5億，幾乎等於折舊額度。</li><li>營運資金變動(Working Capital)： <ul><li>2023年：應收增+7.24億 + 存貨增+8.69億 + 應付減-0.95億 → 營運資金佔用約15.0億</li><li>2024年：應收增-9.09億(回收) + 存貨增-7.18億 + 應付增+4.73億 → 釋放約11.5億</li><li>2025年：應收增-15.13億 + 存貨增-15.0億 + 應付增+10.3億 → 佔用約19.8億</li></ul></li><li>結論：營運資金管理效率在2025年顯著惡化，應收與存貨同步大增侵蝕了本應流入的現金。</li></ul><p><strong>3. FCF穿透分析：</strong></p><ul><li>資本支出(購置固定資產)：2023年101.4億/2024年104.1億/2025年61.2億(較前兩年顯著縮減)</li><li>FCF：2023年-41.1億/2024年-29.0億/2025年+17.1億</li><li>2026年宣布235億三年擴產計劃，預計資本支出將再度攀升至80-100億/年水準，FCF可能再次轉負。</li><li>融資活動：2025年淨償債32.7億(償還長期借款31.9億+短期借款減少2.9億)，顯示公司在FCF轉正後開始降槓桿。</li></ul><p><strong>4. 折舊掩蓋診斷：</strong></p><ul><li>「CFO - 折舊」：2025年為80.9億 - 71.6億 = 9.3億（弱現金流）</li><li>「CFO - 折舊 - 營運資金變動」：9.3億 - (-21.2億) = -11.9億（實質營運仍吃完現金）</li><li>判定：景碩的現金流健康度高度依賴折舊這類非現金費用的挹注。若去除折舊，公司的營運現金流其實非常微薄，這在資本密集的載板產業中屬於結構性特徵，但需警惕：高折舊意味高資本投入比，若未來需求放緩，折舊將從現金流支柱變成損益表的利潤殺手。</li></ul><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><p>以華爾街空頭視角審視，景碩的獲利品質存在兩大罩門：第一，合併報表下大多數淨利歸屬於非控制權益(子公司晶碩光學等)，歸屬母公司業主的獲利僅佔合併淨利的59%(2025年)，大量現金流入來自折舊而非真正的營運盈利。第二，2025年營收成長28.9%的同時，應收帳款增15.1億(+28.6%)、存貨增15.0億(+50.3%)，增速均高於營收增速——這是典型的「擴產塞貨初期現象」，營運資金佔用壓力極高。FCF雖在2025年轉正，但2026年235億擴產計劃將使資本支出再度飆升，屆時公司恐需再次仰賴舉債或現金增資(已有15%稀釋的權利發行計畫)來支應。投資者最應關注的指標是：2026-2027年折舊費用能否被營收成長充分吸收(折舊/營收比需從目前的18.2%降至15%以下)，以及營運資金佔用能否隨產能利用率提升而改善。若無法達成，CFO/淨利比將快速惡化至200%以下，屆時評級將下調至B。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li><code>數據採集器查詢</code>: <code>cash_flow 3189 2023-01-01 2026-04-23 --df</code>（科目：營業活動之淨現金流入、折舊費用、應收帳款增加、存貨增加、應付帳款、取得不動產廠房設備、舉借/償還長期借款）</li><li><code>數據採集器查詢</code>: <code>finance 3189 2023-01-01 2026-04-23 --df</code>（科目：本期淨利、歸屬母公司淨利、非控制權益）</li><li><code>數據採集器查詢</code>: <code>yf_cashflow 3189.TW</code>（交叉驗證：Free Cash Flow, Capital Expenditure, Depreciation, Working Capital變化）</li><li><code>富果法說會備忘錄 20250819</code>: 產品組合與營運展望</li><li><code>Scribd投資報告</code>: 景碩3189投資報告v2_20260320（項目：2026年ASIC訂單及毛利率展望）</li></ul>',21)])])}const g=e(i,[["render",r]]);export{F as __pageData,g as default};
